#!/usr/bin/env python3
"""
Refuerza el prompt del bot de WhatsApp para evitar 'confirmaciones
fantasma': el bot ya no puede decir que una cita fue agendada o que
ya existe sin llamar a book_appointment / list_my_appointments EN EL
MISMO turno y recibir un resultado real. Incluye los fixes anteriores
(no confirmar en error, logs de depuracion).

Ejecutar desde la raiz del repo (carpeta que contiene 'src'):
    python3 apply_whatsapp_bot_antihallucination.py
"""

import base64
from pathlib import Path

WHATSAPP_BOT_B64 = """"""

def main():
    p = Path("src/lib/whatsappBot.ts")
    p.write_bytes(base64.b64decode(WHATSAPP_BOT_B64))
    print(f"escrito: {p} ({p.stat().st_size} bytes)")
    print()
    print("Listo. Luego:")
    print("  git add -A")
    print("  git commit -m 'Bot de WhatsApp: prohibir confirmaciones sin llamar a la herramienta'")
    print("  git push")

if __name__ == "__main__":
    main()